// @category: baseline
int max(int a, int b) { return a > b ? a : b; } int main() { int W = 10; int wt[4] = {2,3,4,5}; int val[4] = {3,4,5,6}; int n = 4; int dp[5][15]; for (int i = 0; i < 5; i++) for (int j = 0; j < 15; j++) dp[i][j] = 0; for (int i = 1; i <= n; i++) for (int w = 1; w <= W; w++) if (wt[i-1] <= w) dp[i][w] = max(val[i-1] + dp[i-1][w-wt[i-1]], dp[i-1][w]); else dp[i][w] = dp[i-1][w]; printf("%d", dp[n][W]); return 0; }
